PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>

SELECT ?team ?grandFinals
WHERE {
  VALUES ?team { wd:Q249679 wd:Q2521385 wd:Q2272176 }
  ?team wdt:P1387 ?grandFinals.
}
ORDER BY DESC(?grandFinals)

PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>

SELECT ?team (COUNT(*) AS ?grandFinals)
WHERE {
  VALUES ?team { wd:Q249679 wd:Q2521385 wd:Q2272176 }
  ?team wdt:P1411 ?grandFinal.
}
GROUP BY ?team
ORDER BY DESC(?grandFinals)

PREFIX wd: <http://www.wikidata.org/entity/>
