PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>

SELECT ?team (COUNT(?event) AS ?appearances)
WHERE {
  VALUES ?team { wd:Q249679 wd:Q2521385 wd:Q2272176 }
  ?team wdt:P3967 ?event.
}
GROUP BY ?team
ORDER BY DESC(?appearances)
